### 2. Game Class (`game.py`)

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = "Red"

    def run(self):
        while not self.board.is_game_over():
            print(f"Current Player: {self.current_player}")
            self.board.display()
            move_str = input("Enter your move (e.g., A1-A2): ").strip().upper()
            try:
                start, end = move_str.split('-')
                start_col, start_row = self._char_to_index(start[0]), int(start[1])
                end_col, end_row = self._char_to_index(end[0]), int(end[1])
                if self.board.move_piece((start_col, start_row), (end_col, end_row)):
                    self.current_player = "White" if self.current_player == "Red" else "Red"
                else:
                    print("Invalid move. Try again.")
            except ValueError:
                print("Invalid input format. Try again.")

        result = self.board.check_winner()
        if result == "Red":
            print("Red wins!")
        elif result == "White":
            print("White wins!")
        else:
            print("It's a draw!")

    def _char_to_index(self, char):
        return ord(char) - ord('A')
```

